+func TestTopicsOverlap(t *testing.T) {
+	tests := []struct {
+		name     string
+		a, b     []Topic
+		expected bool
+	}{
+		{
+			name:     "exact match",
+			a:        []Topic{TopicAuth},
+			b:        []Topic{TopicAuth},
+			expected: true,
+		},
+		{
+			name:     "partial overlap",
+			a:        []Topic{TopicAuth, TopicAPI},
+			b:        []Topic{TopicAPI, TopicDatabase},
+			expected: true,
+		},
+		{
+			name:     "no overlap",
+			a:        []Topic{TopicAuth, TopicUI},
+			b:        []Topic{TopicAPI, TopicDatabase},
+			expected: false,
+		},
+		{
+			name:     "empty first",
+			a:        []Topic{},
+			b:        []Topic{TopicAuth},
+			expected: false,
+		},
+		{
+			name:     "empty second",
+			a:        []Topic{TopicAuth},
+			b:        []Topic{},
+			expected: false,
+		},
+		{
+			name:     "both empty",
+			a:        []Topic{},
+			b:        []Topic{},
+			expected: false,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			result := topicsOverlap(tt.a, tt.b)
+			if result != tt.expected {
+				t.Errorf("topicsOverlap(%v, %v) = %v, want %v",
+					tt.a, tt.b, result, tt.expected)
+			}
+		})
+	}
+}
